class KeyboardShortcuts{constructor(){this.shortcuts=new Map();this.registered=new Set();this.helpModal=null;this.init();}init(){this.registerDefaultShortcuts();this.bindEvents();this.createHelpModal();}registerDefaultShortcuts(){this.register('Ctrl+K','Mở Command Palette',()=>{if(window.commandPalette){window.commandPalette.toggle();}});this.register('Ctrl+?','Mở Help Modal',()=>{this.toggleHelp();});this.register('Escape','Đóng modal/palette',()=>{this.closeAllModals();});this.register('G then D','Về Dashboard',()=>{window.location.href='/admin/dashboard.html';});this.register('G then L','Về Leads',()=>{window.location.href='/admin/leads.html';});this.register('G then P','Về Pipeline',()=>{window.location.href='/admin/pipeline.html';});this.register('G then C','Về Campaigns',()=>{window.location.href='/admin/campaigns.html';});this.register('G then F','Về Finance',()=>{window.location.href='/admin/finance.html';});this.register('N then L','Tạo Lead mới',()=>{window.location.href='/admin/leads.html?action=new';});this.register('N then C','Tạo Campaign mới',()=>{window.location.href='/admin/campaigns.html?action=new';});this.register('Ctrl+S','Lưu thay đổi',(e)=>{e.preventDefault();this.triggerSave();});this.register('Ctrl+E','Export data',()=>{this.triggerExport();});this.register('/','Tìm kiếm',(e)=>{e.preventDefault();this.focusSearch();});this.register('Ctrl+Shift+D','Toggle Dark Mode',()=>{if(window.themeToggle){window.themeToggle.toggle();}});this.register('Ctrl+Shift+N','Mở Notifications',()=>{if(window.notificationBell){window.notificationBell.toggle();}});}register(combo,description,handler){this.shortcuts.set(combo,{description,handler});}bindEvents(){document.addEventListener('keydown',(e)=>{if(['INPUT','TEXTAREA','SELECT'].includes(e.target.tagName)){return;}const combo=this.getCombo(e);if(this.shortcuts.has(combo)){e.preventDefault();this.shortcuts.get(combo).handler(e);return;}if(combo==='G'){this.waitForNextKey();}if(combo==='N'){this.waitForNextKey();}});}getCombo(e){const parts=[];if(e.ctrlKey)parts.push('Ctrl');if(e.shiftKey)parts.push('Shift');if(e.altKey)parts.push('Alt');if(e.metaKey)parts.push('Meta');const key=e.key.toUpperCase();if(!['CONTROL','SHIFT','ALT','META'].includes(key)){parts.push(key);}return parts.join('+');}waitForNextKey(){let timeout;const handleNextKey=(e)=>{clearTimeout(timeout);document.removeEventListener('keydown',handleNextKey);const nextKey=e.key.toUpperCase();const combo=`G then ${nextKey}`;if(this.shortcuts.has(combo)){e.preventDefault();this.shortcuts.get(combo).handler(e);}};document.addEventListener('keydown',handleNextKey);timeout=setTimeout(()=>{document.removeEventListener('keydown',handleNextKey);},1500);}closeAllModals(){if(window.commandPalette&&window.commandPalette.isOpen){window.commandPalette.close();}if(window.notificationBell&&window.notificationBell.isOpen){window.notificationBell.close();}if(this.helpModal&&this.helpModal.open){this.helpModal.close();}}triggerSave(){const saveBtn=document.querySelector('button[type="submit"],.save-btn,[onclick*="save"]');if(saveBtn){saveBtn.click();this.showToast('Đã lưu thay đổi','success');}else{this.showToast('Không tìm thấy nút lưu','info');}}triggerExport(){const exportBtn=document.querySelector('[onclick*="export"],[onclick*="Export"],.export-btn');if(exportBtn){exportBtn.click();}else{this.showToast('Không tìm thấy chức năng export','info');}}focusSearch(){const searchInput=document.querySelector('input[type="text"][placeholder*="Tìm"],input[type="search"],#searchInput,.search-input');if(searchInput){searchInput.focus();}else{if(window.commandPalette){window.commandPalette.open();}}}createHelpModal(){const modal=document.createElement('dialog');modal.id='keyboard-help-modal';modal.className='keyboard-help-modal';modal.innerHTML=`<div class="modal-backdrop"></div><div class="modal-content"><div class="modal-header"><h2><span class="material-symbols-outlined">keyboard</span>Phím Tắt</h2><button class="modal-close" aria-label="Close"><span class="material-symbols-outlined">close</span></button></div><div class="modal-body"><div class="shortcuts-grid">${this.renderShortcutsSection('Điều hướng',['Ctrl+K','G then D','G then L','G then P','G then C','G then F'])}${this.renderShortcutsSection('Hành động',['N then L','N then C','Ctrl+S','Ctrl+E','/'])}${this.renderShortcutsSection('Khác',['Ctrl+?','Ctrl+Shift+D','Ctrl+Shift+N','Escape'])}</div></div></div>`;document.body.appendChild(modal);this.helpModal=modal;modal.querySelector('.modal-close').addEventListener('click',()=>{modal.close();});modal.querySelector('.modal-backdrop').addEventListener('click',()=>{modal.close();});modal.addEventListener('keydown',(e)=>{if(e.key==='Escape'){modal.close();}});}renderShortcutsSection(title,combos){return `<div class="shortcuts-section"><h3>${title}</h3><div class="shortcuts-list">${combos.map(combo=>{const shortcut=this.shortcuts.get(combo);return `<div class="shortcut-item"><kbd class="shortcut-keys">${this.formatCombo(combo)}</kbd><span class="shortcut-desc">${shortcut?.description||''}</span></div>`;}).join('')}</div></div>`;}formatCombo(combo){return combo.replace(/\+/g,'+').replace(' then ',' rồi ');}toggleHelp(){if(this.helpModal){if(this.helpModal.open){this.helpModal.close();}else{this.helpModal.showModal();}}}showHelp(){if(this.helpModal){this.helpModal.showModal();}}showToast(message,type='info'){if(window.toastManager){window.toastManager.show(message,type);}else if(window.errorBoundary){const toast=document.createElement('div');toast.className=`toast toast-${type}`;toast.textContent=message;document.body.appendChild(toast);setTimeout(()=>toast.remove(),3000);}}listShortcuts(){const shortcuts=Array.from(this.shortcuts.entries()).map(([combo,{description}])=>({'Phím': combo,'Chức năng': description}));if(window.location.hostname==='localhost'||window.location.hostname==='127.0.0.1'){console.table(shortcuts);}return shortcuts;}}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>{window.keyboardShortcuts=new KeyboardShortcuts();});}else{window.keyboardShortcuts=new KeyboardShortcuts();}export{KeyboardShortcuts};